--- apps/dav/lib/Connector/Sabre/ZipFolderPlugin.php
+++ apps/dav/lib/Connector/Sabre/ZipFolderPlugin.php
@@ -231,6 +231,12 @@
         $streamer->addEmptyDir($filename);
         $content = $node->getDirectoryListing();
         foreach ($content as $subNode) {
+            // Check if the sub-node is accessible before trying to add it to the streamer
+            if (!$subNode->isReadable()) {
+                $this->logger->info('Skipping unreadable file for zip stream', ['filePath' => $subNode->getPath()]);
+                continue;
+            }
             $this->streamNode($streamer, $subNode, $rootPath);
         }
     }
